={{ $json.agent_message }}

Reply with "yes" to confirm and "no" to deny.

Reference ID: {{ $json.id }}

parameters.jsCode:
const input = $input.first().json;

return [{
  json: {
    status: "proposed",
    reference_id: input.id  // Supabase auto-generated UUID
  }
}];

// FIELD NORMALIZER — PROPOSE ACTION sub-workflow
// Position: after trigger receives agent fields, BEFORE Supabase insert

const raw = $json.fields || {};
const normalized = {};
const action = $json.action || '';

// ─────────────────────────────────────────────────────
// Helper: extract {id} from any representation
// Accepts: "5118344000000350001"  →  {id: "5118344000000350001"}
//          {id: "...", name: "..."} →  {id: "..."}
//          {id: "..."}  →  {id: "..."}
//          "Alphabet Inc"  →  null
// ─────────────────────────────────────────────────────
function toRelObj(val) {
  if (!val) return null;
  if (typeof val === 'object' && !Array.isArray(val) && val.id) {
    const result = { id: String(val.id) };
    if (val.name) result.name = String(val.name);
    return result;
  }
  if (typeof val === 'string') {
    const clean = val.trim();
    if (/^\d{15,20}$/.test(clean)) return { id: clean };
    return null;
  }
  return null;
}

// ─────────────────────────────────────────────────────
// Helper: extract display name string from any representation
// Accepts: {id: "...", name: "Alphabet Inc"}  →  "Alphabet Inc"
//          "Alphabet Inc"  →  "Alphabet Inc"
//          "5118344000000350001"  →  null (pure ID rejected)
// ─────────────────────────────────────────────────────
function toDisplayName(val) {
  if (!val) return null;
  if (typeof val === 'object' && val.name) return String(val.name);
  if (typeof val === 'string' && !/^\d{15,20}$/.test(val.trim())) return val.trim();
  return null;
}

// ─────────────────────────────────────────────────────
// Primary display fields vary by action:
// update_account  → Account_Name must be plain string
// update_deal     → Deal_Name must be plain string
// update_contact / update_lead → Last_Name must be plain string
// All other actions → these are relationship {id} objects
// ─────────────────────────────────────────────────────
const PRIMARY_DISPLAY_ACTIONS = {
  'Account_Name': ['update_account'],
  'Deal_Name':    ['update_deal'],
  'Last_Name':    ['update_contact', 'update_lead'],
};

// ─────────────────────────────────────────────────────
// Canonical key map: any alias → canonical key + transformer
// ─────────────────────────────────────────────────────
const FIELD_RULES = {
  // Relationship fields — must be {id:...} or null
  "Account_Name":         { canon: "Account_Name",      fn: toRelObj },
  "Account_Name.id":      { canon: "Account_Name",      fn: toRelObj },
  "account_name_id":      { canon: "Account_Name",      fn: toRelObj },
  "Contact_Name":         { canon: "Contact_Name",      fn: toRelObj },
  "Contact_Name.id":      { canon: "Contact_Name",      fn: toRelObj },
  "contact_name_id":      { canon: "Contact_Name",      fn: toRelObj },
  "Strategic_Partner":    { canon: "Strategic_Partner", fn: toRelObj },
  "Strategic_Partner.id": { canon: "Strategic_Partner", fn: toRelObj },
  "Owner":                { canon: "Owner",             fn: toRelObj },
  "Owner.id":             { canon: "Owner",             fn: toRelObj },
  "Who_Id":               { canon: "Who_Id",            fn: toRelObj },
  "Who_Id.id":            { canon: "Who_Id",            fn: toRelObj },
  "What_Id":              { canon: "What_Id",           fn: toRelObj },
  "What_Id.id":           { canon: "What_Id",           fn: toRelObj },
  // Boolean fields
  "Listed_Company":       { canon: "Listed_Company",    fn: (v) => v === true || v === "true" || v === "True" || v === 1 },
  // Array fields
  "Service_Type":         { canon: "Service_Type",      fn: (v) => Array.isArray(v) ? v : (v ? [v] : []) },
};

// ─────────────────────────────────────────────────────
// Process each field the agent provided
// ─────────────────────────────────────────────────────
const validationErrors = [];

for (const [rawKey, rawVal] of Object.entries(raw)) {
  // Check if this field is a primary display field for this action
  const displayActions = PRIMARY_DISPLAY_ACTIONS[rawKey];
  if (displayActions && displayActions.includes(action)) {
    // Extract plain string name instead of {id} object
    const name = toDisplayName(rawVal);
    if (name !== null) {
      normalized[rawKey] = name;
    } else {
      validationErrors.push(`${rawKey}: could not extract display name from "${JSON.stringify(rawVal)}" — skipped`);
    }
    continue;
  }

  const rule = FIELD_RULES[rawKey];
  if (rule) {
    const result = rule.fn(rawVal);
    if (result !== null && result !== undefined) {
      normalized[rule.canon] = result;
    } else if (rawKey.includes("Account_Name") || rawKey.includes("Owner")) {
      validationErrors.push(`${rawKey}: "${JSON.stringify(rawVal)}" is not a valid Zoho ID — skipped`);
    }
  } else {
    // Unknown key — pass through as-is
    normalized[rawKey] = rawVal;
  }
}

// ─────────────────────────────────────────────────────
// OWNER VALIDATION — must always be present and valid
// ─────────────────────────────────────────────────────
const VALID_OWNERS = [
  "5118344000000350001",  // Manu
  "5118344000003068049",  // Sparsh
  "5118344000003068001",  // Pranay
  "5118344000004729073",  // Devansh
  "5118344000003068065",  // Vikas
];

if (normalized.Owner && !VALID_OWNERS.includes(normalized.Owner.id)) {
  validationErrors.push(`Owner ID ${normalized.Owner.id} is not in the authorized owner list`);
  delete normalized.Owner;
}

return [{ json: {
  ...$json,
  fields: normalized,
  _validation_warnings: validationErrors
}}];

